import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"FHIR Proxy","description":"","frontmatter":{},"headers":[],"relativePath":"fhir-proxy.md","filePath":"fhir-proxy.md"}'),d={name:"fhir-proxy.md"};function i(n,e,s,c,l,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="fhir-proxy" tabindex="-1">FHIR Proxy <a class="header-anchor" href="#fhir-proxy" aria-label="Permalink to &quot;FHIR Proxy&quot;">​</a></h1><p>The FHIR proxy is the core component of Proxy Smart. It sits between SMART apps and upstream FHIR servers, providing authentication, authorization, consent enforcement, and capability-aware request normalization.</p><h2 id="route-structure" tabindex="-1">Route Structure <a class="header-anchor" href="#route-structure" aria-label="Permalink to &quot;Route Structure&quot;">​</a></h2><p>All proxied FHIR requests follow this URL pattern:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{BASE_URL}/{app-name}/{server_name}/{fhir_version}/{resource_path}</span></span></code></pre></div><p>For example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://proxy.example.com/proxy-smart/hapi-fhir/R4/Patient/123</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Segment</th><th>Description</th></tr></thead><tbody><tr><td><code>server_name</code></td><td>Identifier of a configured FHIR server (see <a href="./admin-ui/fhir-servers">FHIR Servers</a>)</td></tr><tr><td><code>fhir_version</code></td><td>FHIR version — <code>R4</code>, <code>R5</code>, etc. (configured via <code>FHIR_SUPPORTED_VERSIONS</code>)</td></tr><tr><td><code>resource_path</code></td><td>Standard FHIR path — <code>Patient/123</code>, <code>Observation?patient=123</code>, etc.</td></tr></tbody></table><h2 id="request-pipeline" tabindex="-1">Request Pipeline <a class="header-anchor" href="#request-pipeline" aria-label="Permalink to &quot;Request Pipeline&quot;">​</a></h2><p>Every proxied request passes through a five-stage pipeline:</p><h3 id="_1-authentication" tabindex="-1">1. Authentication <a class="header-anchor" href="#_1-authentication" aria-label="Permalink to &quot;1. Authentication&quot;">​</a></h3><p>All requests (except <code>GET /metadata</code>) require a valid Bearer token. The token is validated against Keycloak&#39;s JWKS endpoint. If validation fails, the proxy returns <code>401</code>.</p><h3 id="_2-consent-ial-enforcement" tabindex="-1">2. Consent &amp; IAL Enforcement <a class="header-anchor" href="#_2-consent-ial-enforcement" aria-label="Permalink to &quot;2. Consent &amp; IAL Enforcement&quot;">​</a></h3><p>When consent enforcement is enabled (<code>CONSENT_MODE=enforce</code>), the proxy checks whether the token holder has consent to access the requested resource.</p><ul><li>The consent service evaluates the request against FHIR Consent resources</li><li>Identity Assurance Level (IAL) checks verify the trust level of the Person→Patient link</li><li>If consent is denied, the proxy returns <code>403</code> with details: <ul><li><code>consent_denied</code> — no active consent for this access</li><li><code>ial_verification_failed</code> — identity assurance level insufficient</li></ul></li></ul><p>Consent enforcement has three modes:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Behavior</th></tr></thead><tbody><tr><td><code>disabled</code></td><td>No consent checks (default)</td></tr><tr><td><code>audit-only</code></td><td>Checks consent and logs decisions, but never blocks requests</td></tr><tr><td><code>enforce</code></td><td>Blocks requests without valid consent</td></tr></tbody></table><h3 id="_3-smart-scope-enforcement" tabindex="-1">3. SMART Scope Enforcement <a class="header-anchor" href="#_3-smart-scope-enforcement" aria-label="Permalink to &quot;3. SMART Scope Enforcement&quot;">​</a></h3><p>When enabled (<code>SCOPE_ENFORCEMENT_MODE=enforce</code>), validates that the token&#39;s scopes grant permission for the requested operation.</p><ul><li>Supports SMART v1 format (<code>patient/Observation.read</code>) and v2 format (<code>patient/Observation.cruds</code>)</li><li>Validates resource type and HTTP method against granted scopes</li><li>Wildcard scopes (<code>patient/*.read</code>) match any resource type</li><li>Returns <code>403</code> if the requested operation exceeds granted scopes</li></ul><h3 id="_4-role-based-data-isolation" tabindex="-1">4. Role-Based Data Isolation <a class="header-anchor" href="#_4-role-based-data-isolation" aria-label="Permalink to &quot;4. Role-Based Data Isolation&quot;">​</a></h3><p>When enabled (<code>ROLE_BASED_FILTERING_MODE=enforce</code>), restricts data visibility based on the <code>fhirUser</code> token claim.</p><ul><li><strong>Patient users</strong> — can only access their own data; the proxy injects <code>patient={id}</code> search parameters</li><li><strong>Practitioner users</strong> — see only patients assigned to them via <code>generalPractitioner</code> references; the proxy looks up assigned patients and injects compartment filters</li><li>If a practitioner has no assigned patients, the proxy returns an empty Bundle rather than leaking data</li></ul><h3 id="_5-capability-aware-normalization" tabindex="-1">5. Capability-Aware Normalization <a class="header-anchor" href="#_5-capability-aware-normalization" aria-label="Permalink to &quot;5. Capability-Aware Normalization&quot;">​</a></h3><p>The proxy fetches and caches each upstream server&#39;s <code>CapabilityStatement</code> to enable intelligent request handling.</p><h4 id="strict-mode-per-server-opt-in" tabindex="-1">Strict Mode (per-server opt-in) <a class="header-anchor" href="#strict-mode-per-server-opt-in" aria-label="Permalink to &quot;Strict Mode (per-server opt-in)&quot;">​</a></h4><p>When <code>strictCapabilities</code> is enabled on a FHIR server:</p><ul><li><strong>Interaction checks</strong> — rejects unsupported CRUD operations with <code>405</code></li><li><strong>History checks</strong> — rejects <code>_history</code> requests if the server doesn&#39;t declare history support</li><li><strong>Operation checks</strong> — rejects <code>$operation</code> calls not declared in the CapabilityStatement</li><li><strong>PATCH format checks</strong> — rejects PATCH with unsupported content types with <code>415</code></li></ul><h4 id="search-parameter-normalization-always-active" tabindex="-1">Search Parameter Normalization (always active) <a class="header-anchor" href="#search-parameter-normalization-always-active" aria-label="Permalink to &quot;Search Parameter Normalization (always active)&quot;">​</a></h4><p>Regardless of strict mode, the proxy strips search parameters and <code>_include</code>/<code>_revinclude</code> values not declared by the upstream server. This prevents <code>400</code> errors from servers that reject unknown parameters. Stripped parameters are listed in the <code>x-proxy-stripped-params</code> response header.</p><h2 id="url-rewriting" tabindex="-1">URL Rewriting <a class="header-anchor" href="#url-rewriting" aria-label="Permalink to &quot;URL Rewriting&quot;">​</a></h2><p>Response bodies are rewritten so that all FHIR resource URLs point back through the proxy rather than directly at the upstream server. This ensures clients always route through the proxy&#39;s access control pipeline.</p><h2 id="mtls-support" tabindex="-1">mTLS Support <a class="header-anchor" href="#mtls-support" aria-label="Permalink to &quot;mTLS Support&quot;">​</a></h2><p>Each FHIR server can be configured with mutual TLS (mTLS) certificates for upstream connections. When enabled, the proxy presents a client certificate when connecting to that server. See <a href="./admin-ui/fhir-servers">FHIR Servers</a> for configuration.</p><h2 id="smart-configuration" tabindex="-1">SMART Configuration <a class="header-anchor" href="#smart-configuration" aria-label="Permalink to &quot;SMART Configuration&quot;">​</a></h2><p>Each FHIR server exposes a <code>/.well-known/smart-configuration</code> endpoint through the proxy, dynamically generated from Keycloak&#39;s OIDC configuration and cached for performance.</p><h2 id="monitoring" tabindex="-1">Monitoring <a class="header-anchor" href="#monitoring" aria-label="Permalink to &quot;Monitoring&quot;">​</a></h2><p>All proxied requests are tracked with metrics including server name, HTTP method, resource type, status code, response time, and client ID. These metrics are available via the <a href="./admin-ui/monitoring">Monitoring</a> dashboard.</p><h2 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>FHIR_SERVER_BASE</code></td><td>Comma-separated upstream FHIR server URLs</td><td><code>http://localhost:8081/fhir</code></td></tr><tr><td><code>FHIR_SUPPORTED_VERSIONS</code></td><td>Comma-separated FHIR versions</td><td><code>R4</code></td></tr><tr><td><code>CONSENT_MODE</code></td><td>Consent enforcement mode: <code>disabled</code>, <code>audit-only</code>, <code>enforce</code></td><td><code>disabled</code></td></tr><tr><td><code>CONSENT_ENABLED</code></td><td>Enable consent checks</td><td><code>false</code></td></tr><tr><td><code>CONSENT_CACHE_TTL</code></td><td>Consent decision cache TTL (ms)</td><td><code>60000</code></td></tr><tr><td><code>CONSENT_EXEMPT_CLIENTS</code></td><td>Comma-separated client IDs exempt from consent</td><td>—</td></tr><tr><td><code>CONSENT_REQUIRED_RESOURCE_TYPES</code></td><td>Resource types that always require consent</td><td>—</td></tr><tr><td><code>CONSENT_EXEMPT_RESOURCE_TYPES</code></td><td>Resource types exempt from consent</td><td><code>CapabilityStatement,metadata</code></td></tr><tr><td><code>IAL_ENABLED</code></td><td>Enable Identity Assurance Level checks</td><td><code>false</code></td></tr><tr><td><code>IAL_MINIMUM_LEVEL</code></td><td>Minimum IAL for general access</td><td><code>level1</code></td></tr><tr><td><code>IAL_SENSITIVE_RESOURCE_TYPES</code></td><td>Resource types requiring elevated IAL</td><td>—</td></tr><tr><td><code>IAL_SENSITIVE_MINIMUM_LEVEL</code></td><td>Minimum IAL for sensitive resources</td><td><code>level3</code></td></tr><tr><td><code>IAL_VERIFY_PATIENT_LINK</code></td><td>Verify token patient matches Person.link[]</td><td><code>true</code></td></tr><tr><td><code>IAL_ALLOW_ON_PERSON_LOOKUP_FAILURE</code></td><td>Allow access if Person lookup fails</td><td><code>false</code></td></tr><tr><td><code>IAL_CACHE_TTL</code></td><td>Person resource cache TTL (ms)</td><td><code>300000</code></td></tr><tr><td><code>SCOPE_ENFORCEMENT_MODE</code></td><td>Scope enforcement: <code>disabled</code>, <code>audit-only</code>, <code>enforce</code></td><td><code>disabled</code></td></tr><tr><td><code>ROLE_BASED_FILTERING_MODE</code></td><td>Role-based filtering: <code>disabled</code>, <code>audit-only</code>, <code>enforce</code></td><td><code>disabled</code></td></tr><tr><td><code>PATIENT_SCOPED_RESOURCES</code></td><td>Resource types subject to patient-scoped filtering</td><td><code>Observation,Condition,...</code></td></tr><tr><td><code>SMART_CONFIG_CACHE_TTL</code></td><td>SMART configuration cache TTL (ms)</td><td><code>300000</code></td></tr></tbody></table>',40)])])}const m=t(d,[["render",i]]);export{u as __pageData,m as default};
